.darma-loader-darma-custom-441 {color: var(--loader-color, #2563eb);
   width: 100px;
   display: grid;
   background: radial-gradient(farthest-side, currentColor 98%, #0000) center/30px 100% no-repeat;
   --mask: radial-gradient(12px at left 15px top 50%, #0000 95%, currentColor), radial-gradient(12px at center, #0000 95%, currentColor), radial-gradient(12px at right 15px top 50%, #0000 95%, currentColor);
   -webkit-mask: var(--mask);
   mask: var(--mask);
   -webkit-mask-composite: source-in;
   mask-composite: intersect;
   animation: darma-loader-darma-custom-441-l2 1s infinite alternate;
}
.darma-loader-darma-custom-441:before, .darma-loader-darma-custom-441:after  {
  content: "";
   grid-area: 1/1;
   height: 30px;
   aspect-ratio: 1;
   background: currentColor;
   border-radius: 50%;
}
.darma-loader-darma-custom-441:after  {
  margin-left: auto;
}
@keyframes darma-loader-darma-custom-441-l2  {
  to  {
  width: 50px;
}
}

